3929 std::optional<CmpPredicate> CmpPredicate::getMatching(CmpPredicate A,
3930                                                       CmpPredicate B) {
3931   if (A.Pred == B.Pred)
3932     return A.HasSameSign == B.HasSameSign ? A : CmpPredicate(A.Pred);
3933   if (A.HasSameSign &&
3934       A.Pred == ICmpInst::getFlippedSignednessPredicate(B.Pred))
3935     return B.Pred;
3936   if (B.HasSameSign &&
3937       B.Pred == ICmpInst::getFlippedSignednessPredicate(A.Pred))
3938     return A.Pred;
3939   return {};
3940 }
